load_abundance_matrix <- function(path, marker, threshold_level) {
  df <- read_tsv(path)

  if (!("sample_id" %in% names(df))) {
    stop_fatal(sprintf("%s 缺少 sample_id 列: %s", paste(marker, threshold_level, sep = "/"), path))
  }

  if (nrow(df) == 0 || ncol(df) <= 1) {
    warn_note(sprintf("%s/%s 无有效 taxon，后续将产生空边表。", marker, threshold_level))
    return(list(
      sample_ids = character(),
      taxa = character(),
      mat = matrix(numeric(0), nrow = 0, ncol = 0)
    ))
  }

  sample_ids <- as.character(df$sample_id)
  taxa_cols <- setdiff(names(df), "sample_id")

  mat <- as.matrix(df[, taxa_cols, drop = FALSE])
  suppressWarnings(storage.mode(mat) <- "numeric")
  rownames(mat) <- sample_ids

  # 去掉全零 taxon
  if (ncol(mat) > 0) {
    keep_col <- colSums(mat, na.rm = TRUE) > 0
    mat <- mat[, keep_col, drop = FALSE]
  }

  # 去掉零方差 taxon（SPIEC-EASI 更稳）
  if (ncol(mat) > 0 && nrow(mat) > 1) {
    keep_var <- apply(mat, 2, function(x) stats::var(x, na.rm = TRUE) > 0)
    keep_var[is.na(keep_var)] <- FALSE
    mat <- mat[, keep_var, drop = FALSE]
  }

  list(
    sample_ids = rownames(mat),
    taxa = colnames(mat),
    mat = mat
  )
}

bootstrap_rows <- function(mat, seed, resample_id) {
  if (nrow(mat) <= 1) return(mat)
  set.seed(seed + resample_id)
  idx <- sample(seq_len(nrow(mat)), size = nrow(mat), replace = TRUE)
  out <- mat[idx, , drop = FALSE]
  rownames(out) <- paste0(rownames(mat)[idx], "__boot", seq_along(idx))
  out
}

derive_edge_sign_from_correlation <- function(mat, edges_df) {
  if (nrow(edges_df) == 0) return(edges_df)
  if (ncol(mat) < 2 || nrow(mat) < 2) {
    edges_df$sign <- "+"
    return(edges_df)
  }

  suppressWarnings(cor_mat <- stats::cor(mat, method = "spearman", use = "pairwise.complete.obs"))

  get_sign <- function(a, b) {
    if (!(a %in% colnames(cor_mat)) || !(b %in% colnames(cor_mat))) return("+")
    v <- suppressWarnings(cor_mat[a, b])
    if (is.na(v)) return("+")
    if (v < 0) return("-")
    "+"
  }

  edges_df$sign <- vapply(
    seq_len(nrow(edges_df)),
    function(i) get_sign(edges_df$node1[[i]], edges_df$node2[[i]]),
    character(1)
  )
  edges_df
}

extract_edges_from_spieceasi <- function(se_fit, mat, marker, threshold_level, resample_id) {
  adj <- tryCatch(
    SpiecEasi::getRefit(se_fit),
    error = function(e) NULL
  )

  if (is.null(adj)) {
    warn_note(sprintf("%s/%s/resample=%s 无法提取 refit 邻接矩阵，记为空。", marker, threshold_level, resample_id))
    return(data.frame(
      marker = character(),
      node1 = character(),
      node2 = character(),
      sign = character(),
      weight = numeric(),
      threshold_level = character(),
      resample_id = integer(),
      stringsAsFactors = FALSE
    ))
  }

  if (is.null(dim(adj)) || nrow(adj) < 2 || ncol(adj) < 2) {
    return(data.frame(
      marker = character(),
      node1 = character(),
      node2 = character(),
      sign = character(),
      weight = numeric(),
      threshold_level = character(),
      resample_id = integer(),
      stringsAsFactors = FALSE
    ))
  }

  taxa <- colnames(mat)
  if (length(taxa) != nrow(adj)) {
    # 尽量回填列名
    if (is.null(rownames(adj)) || any(rownames(adj) == "")) {
      rownames(adj) <- taxa
      colnames(adj) <- taxa
    }
  }

  weight_mat <- tryCatch(
    SpiecEasi::symBeta(SpiecEasi::getOptBeta(se_fit), mode = "maxabs"),
    error = function(e) NULL
  )

  edge_idx <- which(adj != 0, arr.ind = TRUE)
  if (nrow(edge_idx) == 0) {
    return(data.frame(
      marker = character(),
      node1 = character(),
      node2 = character(),
      sign = character(),
      weight = numeric(),
      threshold_level = character(),
      resample_id = integer(),
      stringsAsFactors = FALSE
    ))
  }

  # 只取上三角，避免重复边
  edge_idx <- edge_idx[edge_idx[, 1] < edge_idx[, 2], , drop = FALSE]
  if (nrow(edge_idx) == 0) {
    return(data.frame(
      marker = character(),
      node1 = character(),
      node2 = character(),
      sign = character(),
      weight = numeric(),
      threshold_level = character(),
      resample_id = integer(),
      stringsAsFactors = FALSE
    ))
  }

  edges <- data.frame(
    marker = marker,
    node1 = rownames(adj)[edge_idx[, 1]],
    node2 = colnames(adj)[edge_idx[, 2]],
    sign = NA_character_,
    weight = NA_real_,
    threshold_level = threshold_level,
    resample_id = as.integer(resample_id),
    stringsAsFactors = FALSE
  )

  if (!is.null(weight_mat) && !is.null(dim(weight_mat))) {
    edges$weight <- mapply(
      function(a, b) {
        if (!(a %in% rownames(weight_mat)) || !(b %in% colnames(weight_mat))) return(NA_real_)
        as.numeric(weight_mat[a, b])
      },
      edges$node1, edges$node2
    )
    edges$sign <- ifelse(is.na(edges$weight), NA_character_, ifelse(edges$weight < 0, "-", "+"))
  }

  # 若 beta 不可用，则回退到相关系数符号
  need_sign_fallback <- is.na(edges$sign)
  if (any(need_sign_fallback)) {
    tmp <- derive_edge_sign_from_correlation(mat, edges[need_sign_fallback, , drop = FALSE])
    edges$sign[need_sign_fallback] <- tmp$sign
  }

  # weight 仍可保留 NA
  edges$node1 <- as.character(edges$node1)
  edges$node2 <- as.character(edges$node2)

  # 强制 node1/node2 字典序，便于后续 edge_key 一致
  swap_idx <- edges$node1 > edges$node2
  if (any(swap_idx)) {
    tmp <- edges$node1[swap_idx]
    edges$node1[swap_idx] <- edges$node2[swap_idx]
    edges$node2[swap_idx] <- tmp
  }

  edges
}

run_single_spieceasi <- function(mat, cfg, marker, threshold_level, resample_id) {
  if (nrow(mat) < 2 || ncol(mat) < 2) {
    warn_note(sprintf("%s/%s/resample=%s 样本数或 taxon 数不足（需要 >=2），输出空边表。", marker, threshold_level, resample_id))
    return(data.frame(
      marker = character(),
      node1 = character(),
      node2 = character(),
      sign = character(),
      weight = numeric(),
      threshold_level = character(),
      resample_id = integer(),
      stringsAsFactors = FALSE
    ))
  }

  fit <- tryCatch(
    SpiecEasi::spiec.easi(
      X = mat,
      method = cfg$method,
      nlambda = cfg$nlambda,
      lambda.min.ratio = cfg$lambda_min_ratio,
      pulsar.params = list(rep.num = cfg$pulsar_rep_num, seed = cfg$seed + resample_id)
    ),
    error = function(e) e
  )

  if (inherits(fit, "error")) {
    warn_note(sprintf("%s/%s/resample=%s 运行失败，输出空边表。错误: %s",
                      marker, threshold_level, resample_id, conditionMessage(fit)))
    return(data.frame(
      marker = character(),
      node1 = character(),
      node2 = character(),
      sign = character(),
      weight = numeric(),
      threshold_level = character(),
      resample_id = integer(),
      stringsAsFactors = FALSE
    ))
  }

  extract_edges_from_spieceasi(fit, mat, marker, threshold_level, resample_id)
}

run_marker_threshold <- function(marker, threshold_level, cfg) {
  path <- file.path(cfg$prep_dir, sprintf("network_abundance_%s_%s.tsv", marker, threshold_level))
  x <- load_abundance_matrix(path, marker, threshold_level)
  mat0 <- x$mat

  rows <- list()
  log_rows <- list()

  # 主运行：resample_id = 0
  note(sprintf("开始 %s / %s / resample=0", marker, threshold_level))
  e0 <- run_single_spieceasi(mat0, cfg, marker, threshold_level, 0L)
  rows[[length(rows) + 1L]] <- e0
  log_rows[[length(log_rows) + 1L]] <- data.frame(
    marker = marker,
    threshold_level = threshold_level,
    resample_id = 0L,
    n_sample = nrow(mat0),
    n_taxa = ncol(mat0),
    n_edges = nrow(e0),
    status = "OK",
    stringsAsFactors = FALSE
  )

  # bootstrap：resample_id = 1..B
  if (cfg$bootstrap_n > 0L) {
    for (rid in seq_len(cfg$bootstrap_n)) {
      note(sprintf("开始 %s / %s / resample=%s", marker, threshold_level, rid))
      mat_boot <- bootstrap_rows(mat0, cfg$seed, rid)
      eb <- run_single_spieceasi(mat_boot, cfg, marker, threshold_level, rid)
      rows[[length(rows) + 1L]] <- eb
      log_rows[[length(log_rows) + 1L]] <- data.frame(
        marker = marker,
        threshold_level = threshold_level,
        resample_id = as.integer(rid),
        n_sample = nrow(mat_boot),
        n_taxa = ncol(mat_boot),
        n_edges = nrow(eb),
        status = "OK",
        stringsAsFactors = FALSE
      )
    }
  }

  list(
    edges = do.call(rbind, rows),
    runlog = do.call(rbind, log_rows)
  )
}

main <- function() {
  cfg <- parse_args()
  cfg <- prepare_paths(cfg)

  note(sprintf("script      = %s %s", SCRIPT_NAME, SCRIPT_VERSION))
  note(sprintf("env         = %s", cfg$env))
  note(sprintf("code_dir    = %s", cfg$code_dir))
  note(sprintf("result_dir  = %s", cfg$result_dir))
  note(sprintf("prep_dir    = %s", cfg$prep_dir))
  note(sprintf("bootstrap_n = %s", cfg$bootstrap_n))
  note(sprintf("method      = %s", cfg$method))
  note(sprintf("nlambda     = %s", cfg$nlambda))
  note(sprintf("lambda.min.ratio = %s", cfg$lambda_min_ratio))
  note(sprintf("pulsar.rep.num   = %s", cfg$pulsar_rep_num))

  check_required_packages()
  check_required_inputs(cfg)
  check_output_collision(cfg)

  all_edges <- list()
  all_logs <- list()

  for (marker in MARKERS) {
    marker_rows <- list()
    marker_logs <- list()

    for (threshold_level in THRESHOLD_LEVELS) {
      out <- run_marker_threshold(marker, threshold_level, cfg)
      marker_rows[[length(marker_rows) + 1L]] <- out$edges
      marker_logs[[length(marker_logs) + 1L]] <- out$runlog
    }

    marker_edges <- do.call(rbind, marker_rows)
    marker_log <- do.call(rbind, marker_logs)

    out_edge_file <- file.path(cfg$result_dir, sprintf("%s_spieceasi_edges.tsv", marker))
    write_tsv(marker_edges, out_edge_file)
    note(sprintf("已写出 %s", out_edge_file))

    all_edges[[marker]] <- marker_edges
    all_logs[[marker]] <- marker_log
  }

  runlog <- do.call(rbind, all_logs)
  write_tsv(runlog, file.path(cfg$result_dir, "step5A_spieceasi_run_log.tsv"))
  note("已写出 step5A_spieceasi_run_log.tsv")
  note("完成。")
}

