    bootstrap_n = 100L,
    seed = 20260402L,
    method = "mb",
    nlambda = 20L,
    lambda_min_ratio = 1e-2,
    pulsar_rep_num = 20L,
    overwrite = TRUE
  )

  if (length(args) == 0) return(out)

  i <- 1L
  while (i <= length(args)) {
    key <- args[[i]]

    if (key == "--code-dir") {
      out$code_dir <- args[[i + 1L]]; i <- i + 2L; next
    }
    if (key == "--result-dir") {
      out$result_dir <- args[[i + 1L]]; i <- i + 2L; next
    }
    if (key == "--bootstrap-n") {
      out$bootstrap_n <- safe_int(args[[i + 1L]], 100L); i <- i + 2L; next
    }
    if (key == "--seed") {
      out$seed <- safe_int(args[[i + 1L]], 20260402L); i <- i + 2L; next
    }
    if (key == "--method") {
      out$method <- args[[i + 1L]]; i <- i + 2L; next
    }
    if (key == "--nlambda") {
      out$nlambda <- safe_int(args[[i + 1L]], 20L); i <- i + 2L; next
    }
    if (key == "--lambda-min-ratio") {
      out$lambda_min_ratio <- safe_num(args[[i + 1L]], 1e-2); i <- i + 2L; next
    }
    if (key == "--pulsar-rep-num") {
      out$pulsar_rep_num <- safe_int(args[[i + 1L]], 20L); i <- i + 2L; next
    }
    if (key == "--overwrite") {
      out$overwrite <- TRUE; i <- i + 1L; next
    }
    if (key == "--no-overwrite") {
      out$overwrite <- FALSE; i <- i + 1L; next
    }

    stop_fatal(sprintf("未知参数: %s", key))
  }

  out
}

